import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer';
import { CombatPopupParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/CombatPopupParser';

export class CombatPopupEvent extends MessageEvent implements IMessageEvent {
    constructor(callback: Function) {
        super(callback, CombatPopupParser);
    }

    public getParser(): CombatPopupParser {
        return this.parser as CombatPopupParser;
    }
}